#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=5e5+10,BK=864;struct node{int l,r,idx,k;}q[N];
int n,Q,a[N],c[N],cc[N/BK+10],loc[N],ql[N/BK+10],qr[N/BK+10],blk,ans[N],L,R;
inline void ins(const int &x){++c[x];++cc[loc[x]];} inline void del(const int &x){--c[x];--cc[loc[x]];}
inline int qry(const int &Lm){rep(1,blk,B)if(cc[B]>Lm){rep(ql[B],qr[B],i)if(c[i]>Lm)return i;}return -1;}
int main()
{
	n=read();Q=read();rep(1,n,i)a[i]=read(),loc[i]=(i-1)/BK+1;rep(1,Q,i)q[i].l=read(),q[q[i].idx=i].r=read(),q[i].k=read();
	std::sort(q+1,q+Q+1,[&](const node&x,const node&y){return loc[x.l]==loc[y.l]?(loc[x.l]&1?x.r<y.r:x.r>y.r):x.l<y.l;});
	blk=loc[n];rep(1,blk,i)ql[i]=qr[i-1]+1,qr[i]=i*BK;qr[blk]=n;L=q[1].l;R=L-1;
	rep(1,Q,i)
	{
		while(R<q[i].r)ins(a[++R]);while(L>q[i].l)ins(a[--L]);
		while(R>q[i].r)del(a[R--]);while(L<q[i].l)del(a[L++]);
		ans[q[i].idx]=qry((R-L+1)/q[i].k);
	}
	rep(1,Q,i)printf("%d\n",ans[i]);return 0;
}
